708	void ALFPWorldMapPlayerController::OnHireMarketWidgetClosed()
709	{
710		UE_LOG(LogTemp, Log, TEXT("雇佣市场: 面板已关闭"));
711	
712		if (bReturnToTownAfterHireMarketClose && TownWidget && TownWidget->IsInViewport())
713		{
714			TownWidget->SetVisibility(ESlateVisibility::Visible);
715		}
716	
717		bReturnToTownAfterHireMarketClose = false;
718	}
719	
720	void ALFPWorldMapPlayerController::OpenTown(ALFPWorldMapNode* TownNode)
721	{
722		if (!TownNode || !TownWidgetClass) return;
723	
724		// 解析建筑列表
725		TArray<ELFPTownBuildingType> BuildingTypes = LFPTownUtils::ParseBuildingList(TownNode->TownBuildingList);
726	
727		if (BuildingTypes.Num() == 0)
728		{
729			UE_LOG(LogTemp, Warning, TEXT("城镇节点 %d: 建筑列表为空"), TownNode->NodeID);
730			return;
731		}
732	
733		// 创建或显示 TownWidget
